// -*- coding: UTF-8 -*-
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    bool validateStackSequences(vector<int>& pushed, vector<int>& popped) {
        stack.clear();
        int i = 0;
        for (int num : pushed) {
            stack.push_back(num);
            while (!stack.empty() && stack.back() == popped[i]) {
                stack.pop_back();
                i++;
            }
        }
        return i == popped.size();
    }
};
signed main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    Solution solution;
    int T;
    cin >> T;
    while (T--) {
        vector<int> pushed, popped;
        cin >> T;
        for (int i = 0, x; i < T; ++i) {
            cin >> x;
            if (i % 2 == 0) pushed.push_back(x);
            else popped.push_back(x);
        }
        cout << (solution.validateStackSequences(pushed, popped) ? '1' : '0') << '
';
    }
    return 0;
}
